SELECT i.inquiry_id, m.member_id, i.category, i.title, i.status, i.created_at, i.processed_at, r.ad_id AS ad_id, r.created_at AS response_created_at FROM inquiry i JOIN member m ON i.member_idx = m.member_idx LEFT JOIN response r ON i.inquiry_id = r.inquiry_id
i.category = #{category}
AND i.status = #{status}
AND (i.title LIKE CONCAT('%', #{keyword}, '%') OR m.member_id LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY CASE i.status WHEN '접수' THEN 0 WHEN '보류' THEN 1 WHEN '답변완료' THEN 2 ELSE 3 END, i.inquiry_id DESC LIMIT #{startRow}, #{pageSize}

SELECT COUNT(*) FROM inquiry i JOIN member m ON i.member_idx = m.member_idx
i.category = #{category}
AND (i.title LIKE CONCAT('%', #{keyword}, '%') OR m.member_id LIKE CONCAT('%', #{keyword}, '%'))
